import{_ as r,o as t,c as p,j as a,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"麦田里的守望者","description":"","frontmatter":{},"headers":[],"relativePath":"3.见证强化/见证物品与改造/麦田里的守望者.md","filePath":"3.见证强化/见证物品与改造/麦田里的守望者.md"}'),o={name:"3.见证强化/见证物品与改造/麦田里的守望者.md"};function d(_,e,l,b,i,c){return t(),p("div",null,[...e[0]||(e[0]=[a("h1",{id:"麦田里的守望者",tabindex:"-1"},[n("麦田里的守望者 "),a("a",{class:"header-anchor",href:"#麦田里的守望者","aria-label":'Permalink to "麦田里的守望者"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"汹涌疾风026")])])],-1),s('<h1 id="麦田里的守望者-1" tabindex="-1">麦田里的守望者 <a class="header-anchor" href="#麦田里的守望者-1" aria-label="Permalink to &quot;麦田里的守望者&quot;">​</a></h1><p>麦田里的守望者</p><p>3见证点</p><p>西边山上，九只母狼<br> 东边山上，一轮月亮<br> 反复抱过的妻子是枪<br> 枪是沉睡爱情的村庄</p><p>特殊的，麦田里的守望者需使用猎手之枪进行换购，在使用猎手之枪经历三场影片后，可以使用标注的见证点数换购麦田里的守望者。</p><p>武器采用基础远程武器中的狙击枪模板，具有全部相关特性，在其基础上提升9L武器伤害，并额外具有1点高速。</p><p>这把狙击枪，整体呈深麦色，如若不仔细分辨，可能会将它错认作一片倒塌的麦丛，如仔细观察，还会发现木制枪柄上生出一圈又一圈的年轮。</p><p>大地之子<br> “祖父死在这里，父亲死在这里，我也会死在这里。<br> 你是唯一一块埋人的地方。”<br> 当你身处于草地、田野、森林等有大量植被的环境中时：<br> ①你的身周将快速催长出大量常见植物，如杂草、不知名的野花，这些催生出的植物将会连成一道仅保护你的壁垒，能够为你提供5点遮蔽防御。<br> ②并获得C级自然本质的反侦测能力，同时，被你亲手埋葬于这类环境中的躯体将始终视为遗体保存完好。</p><p>无尽守望<br> “大风从东吹到西，从北刮到南，无视黑夜和黎明。<br> 你说的曙光究竟是什么意思。”<br> 一场景一次，一次行动轮开始时，若你无法被场景中的任何敌人定位，无尽守望将开始生效，此时你始终视为处于先攻队列的最末端。在每个行动轮开始时，需选择是否跳过你自身的回合，若不跳过，则这时无尽守望将会失效；若跳过你的回合，则：<br> ①每一个行动轮结束时，若无尽守望还在生效，根据无尽守望生效的轮次，立即获得等同于你的传奇感知*8/4/2点的瞄准上限。同时，若你的基础AP高于14点，则还会每超过1点，就再额外获得6点瞄准加值。这些获得的上限和加值将在无尽守望失效后的下一次攻击结束时失去。<br> ②当无尽守望失效时，这一能力将立即开始生效，你每跳过一轮，就在这回合开始时额外获得1点仅能用于施展射击技艺的AP，这一轮结束时立即失去这些ap。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
